mapper.select:
SELECT t1.ID, t1.CONTRACT_NAME, t1.CONTRACT_CODE, t1.CONTRACT_AMOUNT, t1.START_DATE, t1.END_DATE, t1.APPLY_SCOPE, t1.STATUS, t1.CONTRACT_TYPE, t2.DICT_LABEL contractTypeLable
FROM E_COST_CONTRACT_INFO t1 LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUSAND t2.DICT_TYPE = 'CONTRACT_TYPE' where 1 = 1
and CONTRACT_NAME like #{contractNameLike}
and CONTRACT_CODE like #{contractCodeLike}
AND START_DATE >= #{startDate}
and END_DATE <= #{endDate}
order by CREATED_TIME DESC
